var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Fix 5: Captive dependency — Singleton captured a Scoped service, which
//        .NET 9 ValidateScopes (now on by default in Development) rejects.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// Fix 1: HttpClientFactory now defaults to SocketsHttpHandler in .NET 9.
//        The cast to HttpClientHandler would throw InvalidCastException.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });
// Fix 2: ForwardedHeadersMiddleware in .NET 9 ignores X-Forwarded-* headers
//        from proxies not in KnownProxies/KnownNetworks. Configure your
//        trusted proxy addresses here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: Add your actual proxy addresses, e.g.:
    // options.KnownProxies.Add(System.Net.IPAddress.Parse("10.0.0.1"));
});
// Fix 3: HttpClientFactory Trace-level logs now redact all header values by
//        default. Allowlist the non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(header =>
        header != "X-Request-Id"
        && header != "X-Correlation-Id"
        && header != "Cache-Control"
        && header != "Accept"
        && header != "Content-Type"));
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

